import{_ as n,o,c as a,a2 as l}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Function Calling Deep Dive","description":"Advanced function calling patterns including parallel tool calls, nested tool use, and handling ambiguous or invalid tool requests.","frontmatter":{"title":"Function Calling Deep Dive","description":"Advanced function calling patterns including parallel tool calls, nested tool use, and handling ambiguous or invalid tool requests."},"headers":[],"relativePath":"learn/linear/03-understanding-llms/08-function-calling-deep-dive.md","filePath":"learn/linear/03-understanding-llms/08-function-calling-deep-dive.md"}'),e={name:"learn/linear/03-understanding-llms/08-function-calling-deep-dive.md"};function t(p,s,c,r,i,y){return o(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="function-calling-deep-dive" tabindex="-1">Function Calling Deep Dive <a class="header-anchor" href="#function-calling-deep-dive" aria-label="Permalink to &quot;Function Calling Deep Dive&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How parallel tool calling works and when models choose to invoke multiple tools simultaneously</li><li>Strategies for handling malformed tool calls, missing parameters, and type mismatches</li><li>Advanced patterns like tool choice forcing, tool-only responses, and conditional tool availability</li></ul></blockquote><p>The previous subchapter covered the tool use protocol fundamentals. Now let&#39;s dig into the advanced patterns that separate a basic agent from a robust one. In production, the model will generate malformed tool calls, pass wrong types, call tools that do not make sense in context, and occasionally hallucinate tool names that do not exist. Your agent needs to handle all of these gracefully.</p><h2 id="parallel-tool-calls" tabindex="-1">Parallel Tool Calls <a class="header-anchor" href="#parallel-tool-calls" aria-label="Permalink to &quot;Parallel Tool Calls&quot;">​</a></h2><p>When the model needs information from multiple independent sources, it can request several tool calls in a single response. This is not just a convenience -- it is a significant performance optimization.</p><p>Consider a scenario where the model needs to understand a project&#39;s structure. Instead of reading files one at a time:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Turn 1: Model calls read_file(&quot;Cargo.toml&quot;)</span></span>
<span class="line"><span>Turn 2: Agent returns Cargo.toml contents</span></span>
<span class="line"><span>Turn 3: Model calls read_file(&quot;src/main.rs&quot;)</span></span>
<span class="line"><span>Turn 4: Agent returns main.rs contents</span></span>
<span class="line"><span>Turn 5: Model calls read_file(&quot;src/lib.rs&quot;)</span></span>
<span class="line"><span>Turn 6: Agent returns lib.rs contents</span></span></code></pre></div><p>The model can request all three in one turn:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;text&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Let me examine the project structure.&quot;</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01AAA&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Cargo.toml&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01BBB&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01CCC&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/lib.rs&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This reduces a 6-turn interaction to 2 turns (request + results), cutting latency by two-thirds. Your agent should execute these in parallel:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">task</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">JoinSet</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> tasks </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> JoinSet</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> tool_call </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> tool_calls </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">    tasks</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">spawn</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> move</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> result</span><span style="color:#94E2D5;"> =</span><span style="color:#89B4FA;font-style:italic;"> execute_tool</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">tool_call</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">tool_call</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">        (</span><span style="color:#CDD6F4;">tool_call</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">id</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">(),</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">    });</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> results </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">while</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Some</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Ok</span><span style="color:#9399B2;">((</span><span style="color:#CDD6F4;">id</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">)))</span><span style="color:#94E2D5;"> =</span><span style="color:#CDD6F4;"> tasks</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join_next</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    results</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">ToolResult</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> tool_use_id</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> id</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> content</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;"> });</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>However, not all parallel tool calls are truly independent. If the model calls <code>write_file</code> and then <code>shell(&quot;cargo check&quot;)</code> in the same turn, the shell command depends on the file write completing first. Your agent needs to be smart about execution order. A safe heuristic: execute read operations in parallel, but execute write operations and their dependent checks sequentially.</p><h2 id="the-tool-choice-parameter" tabindex="-1">The <code>tool_choice</code> Parameter <a class="header-anchor" href="#the-tool-choice-parameter" aria-label="Permalink to &quot;The \`tool_choice\` Parameter&quot;">​</a></h2><p>Both Anthropic and OpenAI let you control whether the model must use a tool, and optionally which tool.</p><p><strong>Anthropic&#39;s <code>tool_choice</code>:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tool_choice</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;auto&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td><code>{&quot;type&quot;: &quot;auto&quot;}</code></td><td>Model decides whether to use tools (default)</td></tr><tr><td><code>{&quot;type&quot;: &quot;any&quot;}</code></td><td>Model must use at least one tool</td></tr><tr><td><code>{&quot;type&quot;: &quot;tool&quot;, &quot;name&quot;: &quot;read_file&quot;}</code></td><td>Model must call this specific tool</td></tr></tbody></table><p><strong>OpenAI&#39;s <code>tool_choice</code>:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tool_choice</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;auto&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td><code>&quot;auto&quot;</code></td><td>Model decides whether to use tools (default)</td></tr><tr><td><code>&quot;required&quot;</code></td><td>Model must use at least one tool</td></tr><tr><td><code>{&quot;type&quot;: &quot;function&quot;, &quot;function&quot;: {&quot;name&quot;: &quot;read_file&quot;}}</code></td><td>Model must call this specific tool</td></tr><tr><td><code>&quot;none&quot;</code></td><td>Model must not use tools</td></tr></tbody></table><p>Forcing tool use is valuable in specific situations:</p><ul><li><strong>First turn of an agent session</strong>: force a <code>read_file</code> or <code>list_directory</code> tool call to ensure the model inspects the codebase before answering.</li><li><strong>After a failed tool call</strong>: force the same tool with corrected parameters to ensure the model retries rather than giving up.</li><li><strong>Pipeline steps</strong>: when your agent has a fixed workflow (e.g., &quot;always run tests after editing&quot;), force the <code>shell</code> tool.</li></ul><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python agent frameworks like LangChain use the concept of &quot;tool binding&quot; where you can force the next step in a chain to use a specific tool. In Rust, you control this by setting the <code>tool_choice</code> parameter in your API request struct. The pattern is the same -- you are overriding the model&#39;s autonomous decision-making when you need deterministic behavior.</p></div><h2 id="handling-malformed-tool-calls" tabindex="-1">Handling Malformed Tool Calls <a class="header-anchor" href="#handling-malformed-tool-calls" aria-label="Permalink to &quot;Handling Malformed Tool Calls&quot;">​</a></h2><p>Models generate tool call arguments as JSON, and that JSON can be malformed in several ways:</p><p><strong>Missing required parameters:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;write_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // &quot;content&quot; is missing but required</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Wrong types:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;shell&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">command</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;ls&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;-la&quot;</span><span style="color:#9399B2;">]</span><span style="color:#6C7086;font-style:italic;">  // Array instead of string</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Extra unexpected parameters:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;read_file&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;src/main.rs&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">encoding</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;utf-8&quot;</span><span style="color:#6C7086;font-style:italic;">  // Not in the schema</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Hallucinated tool names:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;search_code&quot;</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">  // This tool doesn&#39;t exist</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">query</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;fn main&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Your agent should handle each of these:</p><ol><li><p><strong>Missing parameters</strong>: Return an error result explaining which parameter is missing. The model will typically retry with the correct parameters.</p></li><li><p><strong>Wrong types</strong>: Attempt a reasonable coercion (e.g., join an array into a string). If coercion is not possible, return an error.</p></li><li><p><strong>Extra parameters</strong>: Ignore them. The tool does not need them, and rejecting the call would be needlessly strict.</p></li><li><p><strong>Hallucinated tools</strong>: Return an error listing the available tools. This is surprisingly common when the model is trying to accomplish something that the available tools do not directly support.</p></li></ol><p>Here is a robust error result for a hallucinated tool:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_result&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">tool_use_id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01XYZ&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">is_error</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Error: Unknown tool &#39;search_code&#39;. Available tools are: read_file, write_file, shell, list_directory. To search for code, use the shell tool with grep or ripgrep.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This error message does three things: identifies the problem, lists alternatives, and suggests a workaround. The model almost always recovers from this.</p><h2 id="conditional-tool-availability" tabindex="-1">Conditional Tool Availability <a class="header-anchor" href="#conditional-tool-availability" aria-label="Permalink to &quot;Conditional Tool Availability&quot;">​</a></h2><p>Sometimes you want to change which tools are available based on context. For example:</p><ul><li><strong>Dangerous operations</strong>: Remove the <code>shell</code> tool when the user has not granted execution permissions.</li><li><strong>Workflow phases</strong>: In the &quot;planning&quot; phase, provide only read tools. In the &quot;implementation&quot; phase, add write tools.</li><li><strong>Cost optimization</strong>: Remove expensive tools (like web search) when the task does not need them.</li></ul><p>Since tool definitions are part of the API request, you can change them on every call:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> get_tools_for_phase</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">phase</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">AgentPhase</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Tool</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> tools </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> vec!</span><span style="color:#9399B2;">[</span><span style="color:#89B4FA;font-style:italic;">read_file_tool</span><span style="color:#9399B2;">(),</span><span style="color:#89B4FA;font-style:italic;"> list_directory_tool</span><span style="color:#9399B2;">()];</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> phase </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        AgentPhase</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Planning</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            // Read-only tools during planning</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        AgentPhase</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Implementation</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">            tools</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">write_file_tool</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#CDD6F4;">            tools</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">shell_tool</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        AgentPhase</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Review</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">            tools</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">shell_tool</span><span style="color:#9399B2;">());</span><span style="color:#6C7086;font-style:italic;"> // For running tests</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">    tools</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Be aware that changing available tools mid-conversation can confuse the model if previous messages reference tools that are no longer available. If you remove a tool, consider whether the conversation history contains calls to that tool, and if so, whether the model might try to call it again.</p><h2 id="tool-descriptions-that-improve-accuracy" tabindex="-1">Tool Descriptions That Improve Accuracy <a class="header-anchor" href="#tool-descriptions-that-improve-accuracy" aria-label="Permalink to &quot;Tool Descriptions That Improve Accuracy&quot;">​</a></h2><p>The quality of tool descriptions directly affects how reliably the model uses tools. Here are patterns that work well:</p><p><strong>Include return value descriptions:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Read a file&#39;s contents. Returns the full text content of the file, or an error message if the file does not exist or cannot be read.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Include usage guidance:</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Execute a shell command. Returns stdout, stderr, and exit code. Use this for build commands (cargo check, cargo test), file operations (ls, find, grep), and version control (git status, git diff). Commands run in the project root directory by default.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Include negative guidance (when not to use):</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Write content to a file, creating it if it doesn&#39;t exist or overwriting if it does. IMPORTANT: Always read the file first to understand its current contents before writing. Do not use this to append to files — read the current content, modify it, and write the complete new content.&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The description is essentially a mini system prompt for each tool. It shapes when the model decides to use the tool and how it constructs the arguments.</p><h2 id="the-tool-result-feedback-loop" tabindex="-1">The Tool Result Feedback Loop <a class="header-anchor" href="#the-tool-result-feedback-loop" aria-label="Permalink to &quot;The Tool Result Feedback Loop&quot;">​</a></h2><p>One of the most powerful patterns in agent design is using tool results to guide subsequent tool calls. The model reads the result, reasons about it, and decides what to do next:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Model: read_file(&quot;src/main.rs&quot;)</span></span>
<span class="line"><span>Result: [file contents with a compilation error]</span></span>
<span class="line"><span>Model: &quot;I see a type mismatch on line 45. Let me fix it.&quot;</span></span>
<span class="line"><span>Model: write_file(&quot;src/main.rs&quot;, [corrected contents])</span></span>
<span class="line"><span>Result: &quot;File written successfully&quot;</span></span>
<span class="line"><span>Model: shell(&quot;cargo check&quot;)</span></span>
<span class="line"><span>Result: &quot;error[E0308]: mismatched types on line 52...&quot;</span></span>
<span class="line"><span>Model: &quot;There&#39;s another error. Let me fix that too.&quot;</span></span></code></pre></div><p>This iterative cycle of observe-reason-act is the core of agent intelligence. The quality of your tool results directly determines how well the model can reason. Include enough context for the model to understand the situation:</p><ul><li>For file reads: the complete contents, not a summary</li><li>For shell commands: stdout, stderr, and the exit code</li><li>For errors: the full error message, not just &quot;failed&quot;</li></ul><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Production agents like Claude Code invest heavily in the quality of tool results. Shell command results include the exit code, truncated but informative output, and timing information. File read results include line numbers. Error results include suggestions for common fixes. This rich feedback is what enables the model to self-correct through multiple iterations rather than failing on the first error.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Parallel tool calls reduce interaction turns and latency -- execute independent calls concurrently, but maintain ordering for dependent operations like write-then-verify</li><li>The <code>tool_choice</code> parameter lets you force tool use (<code>any</code>/<code>required</code>), force a specific tool, or prevent tool use entirely -- use this for deterministic workflow steps</li><li>Handle malformed tool calls gracefully: tolerate extra parameters, attempt type coercion, return informative errors for missing parameters and hallucinated tool names</li><li>Tool descriptions are mini system prompts -- include what the tool returns, when to use it, and when not to use it for the best model behavior</li><li>Rich, detailed tool results enable the model&#39;s observe-reason-act loop, which is the foundation of agent intelligence</li></ul>`,61)])])}const h=n(e,[["render",t]]);export{d as __pageData,h as default};
